import pyotp
from qrcode import QRcode
import datetime

class TotpAuth:
    def __init__(self, user_id):
        self.user_id = user_id
        self.totp_secret = self.generate_totp_secret()

    @staticmethod
    def generate_totp_secret():
        return pyotp.random_base32()

    def create_qr_code(self):
        totp = pyotp.TOTP(self.totp_secret)
        qr_data = f"otpauth://totp/{self.user_id}?secret={self.totp_secret}&issuer=YourCompany"
        QRcode.write(qr_data, "qrcode.png")

    @staticmethod
    def validate_totp_code(totp_secret, totp_code):
        try:
            totp = pyotp.TOTP(totp_secret)
            return totp.verify(totp_code)
        except Exception as e:
            print(f"Error validating TOTP code: {e}")
            return False

def main():
    user_id = "user123"
    auth = TotpAuth(user_id)

    # Generate QR code
    auth.create_qr_code()

    # Validate TOTP code
    totp_secret = auth.totp_secret
    totp_code = input("Enter your TOTP code: ")
    if auth.validate_totp_code(totp_secret, totp_code):
        print("TOTP code is valid")
    else:
        print("Invalid TOTP code")

if __name__ == "__main__":
    main()